    envSetByteArrayRegion(result, 0, paddedLen, reinterpret_cast<jbyte (output));

    // 释放资源
    envReleaseByteArrayElements(data, (jbyte ) dataBytes, 0);
    free(paddedData);
    free(output);

    // 释放资源
    delete[] keyBytes;
    delete[] ivBytes;

    return result;
}
