`
__int64 __fastcall sub_2D17C(__int64 result, __int64 a2)
{
  int i; // [xsp+Ch] [xbp14h]

  if ( dword_6DE28 != 1 )
  {
    for ( i = 0; i != 6; ++i )
      (_BYTE )(result + i) = (_BYTE )(a2 + i % 0x1Au) & ~(_BYTE )(a2 + 26 + i) | (_BYTE )(a2 + 26 + i) & ~(_BYTE )(a2 + i % 0x1Au);
    dword_6DE28 = 1;
  }
  return result;
}
