`
extern "C"
JNIEXPORT jobjectArray JNICALL
Java_com_cyrus_example_fart_AntiFART_listLoadedFiles(JNIEnv env, jclass) {
    std::ifstream maps("/proc/self/maps");
    std::string line;
    std::vector<std::string paths;

    while (std::getline(maps, line)) {
        std::size_t pathPos = line.find('/');
        if (pathPos != std::string::npos) {
            std::string path = line.substr(pathPos);
            if (std::find(paths.begin(), paths.end(), path) == paths.end()) {
                paths.push_back(path);
            }
        }
    }

    jclass stringClass = envFindClass("java/lang/String");
    jobjectArray result = envNewObjectArray(paths.size(), stringClass, nullptr);
    for (size_t i = 0; i < paths.size(); ++i) {
        envSetObjectArrayElement(result, i, envNewStringUTF(paths[i].c_str()));
    }

    return result;
}
