// Raw try_item.
struct TryItem {
  uint32_t start_addr_;
  uint16_t insn_count_;
  uint16_t handler_off_;
};
`




| 字段名 | 类型 | 说明 |
| |  | |
| start_addr_ | uint32_t | 指向 code_iteminsns[] 的某个偏移，表示 try 块的起始位置（单位为 16bit 指令） |
| insn_count_ | uint16_t | try 块中包含多少条指令（单位为 16bit 指令） |
| handler_off_ | uint16_t | 是 hander 结构的偏移，这个偏移是从 insns_ + sizeof(TryItem)  tries_size_  开始的，用于描述 catch/finally 的处理逻辑 |


完整示例：带各种 TryItem 情况的 Kotlin 类

`
package com.cyrus.example.shell

class TryItemExample {

    // ✅ 0. 没有 trycatch（不会生成 TryItem）
    fun noTryCatch(): Int {
        val a = 1
        val b = 2
        return a + b
    }

    // ✅ 1. 简单 trycatch（一个 TryItem）
    fun simpleTryCatch(): String {
        return try {
            val x = 10 / 2
            "Result: $x"
        } catch (e: Exception) {
            "Caught Exception"
        }
    }

    // ✅ 2. 多个 catch 分支（一个 TryItem，多个 handler entry）
    fun multiCatch(input: String?): Int {
        return try {
            input!!.length
        } catch (e: NullPointerException) {
            1
        } catch (e: Exception) {
            2
        }
    }

    // ✅ 3. trycatchfinally（一个 TryItem + finally handler）
    fun tryCatchFinally(): Int {
        return try {
            1 / 0
        } catch (e: ArithmeticException) {
            100
        } finally {
            println("finally block executed")
        }
    }

    // ✅ 4. 嵌套 trycatch（两个 TryItem，嵌套结构）
    fun nestedTryCatch(): String {
        return try {
            try {
                val data = "123".toInt()
                "Parsed: $data"
            } catch (e: NumberFormatException) {
                "Inner Catch"
            }
        } catch (e: Exception) {
            "Outer Catch"
        }
    }

    // ✅ 5. 只有 finally，无 catch（一个 TryItem，无 handler entry）
    fun onlyFinally(): Int {
        try {
            val x = 1 + 1
        } finally {
            println("executing finally without catch")
        }
        return 0
    }

    // ✅ 6. 多个独立 try 块（多个 TryItem，非嵌套）
    fun multipleTryBlocks(): Int {
        try {
            val a = 10 / 2
        } catch (e: Exception) {
            println("First catch")
        }

        try {
            val b = "abc".toInt()
        } catch (e: NumberFormatException) {
            println("Second catch")
        }

        return 0
    }
}
`


