function toJson(obj) {
    try {
        const GsonUtils = Java.use("com..helios.sdk.utils.GsonUtils");

        // 直接调用 LIZJ 静态方法
        const jsonString = GsonUtils.LIZJ(obj);

        return jsonString ? jsonString.toString() : "";
    } catch (err) {
        console.error("Error calling GsonUtils.LIZJ:", err);
        return "";
    }
}
