        return this.mBodyMd5Stub;
    }

    @Override // com..retrofit2.mime.AbsTypedOutput
    public String mimeType() {
        return "application/xwwwformurlencoded; charset=UTF8";
    }

    @Override // com..retrofit2.mime.AbsTypedOutput
    public void writeTo(OutputStream outputStream) {
