 JNI 相关调用



在 DalvikVM 中有 _JavaVM 指针和 _JNIEnv 指针，就是用来实现 JNI 接口调用的






JniNativeInterface 一系列接口函数就是在这里实现的






创建 Dalvik 虚拟机实例

`
// 创建一个 Dalvik 虚拟机实例
VM vm = emulator.createDalvikVM();
// 启用虚拟机的调试输出
vm.setVerbose(true);
`


 1. 调用 JNI_Onload



在 cpp 中实现 JNI_Onload 函数并动态注册 add 方法到 UnidbgActivity

`
// native add 函数
extern "C" JNIEXPORT jint JNICALL native_add(
        JNIEnv env, jobject thiz, jint a, jint b, jint c, jint d, jint e, jint f) {
    // 计算并返回和
    return a + b + c + d + e + f;
}

// 动态注册 add 方法
extern "C" JNIEXPORT jint JNICALL JNI_OnLoad(JavaVM vm, void reserved) {
    JNIEnv env = nullptr;
    if (vmGetEnv(reinterpret_cast<void(&env), JNI_VERSION_1_6) != JNI_OK) {
        return JNI_ERR;
    }

    // 获取 UnidbgActivity 类
    jclass clazz = envFindClass("com/cyrus/example/unidbg/UnidbgActivity");
    if (clazz == nullptr) {
        return JNI_ERR;
    }

    // 动态注册 add 方法
    JNINativeMethod methods[] = {
            {"add", "(IIIIII)I", (void)native_add}
    };

    // 注册方法
    if (envRegisterNatives(clazz, methods, sizeof(methods) / sizeof(methods[0])) < 0) {
        return JNI_ERR;
    }

    return JNI_VERSION_1_6;
}
`


