 Android 示例代码



在 com.cyrus.example.unidbg.UnidbgActivity 编写一个静态变量 a 和非静态变量 b，还有  base64 方法。



代码如下：

`
package com.cyrus.example.unidbg

import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import android.util.Base64

class UnidbgActivity : AppCompatActivity() {

    companion object {
        // 静态变量 a
        var a: String? = null
    }

    // 非静态变量 b
    var b: String? = null

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_unidbg)

        // 初始化静态变量 a 和 非静态变量 b
        a = "StaticA"
        b = "NonStaticB"
    }

    // Base64 方法
    fun base64(content: String): String {
        val combined = (a ?: "") + content + (b ?: "")
        return Base64.encodeToString(combined.toByteArray(), Base64.NO_WRAP)
    }

    // Native 方法 sign
    external fun sign(content: String): String
}
`


再实现一个 native 方法 sign 接受一个字符串 content，将 java 层 UnidbgActivity 中 静态变量 a  + content + 非静态变量 b 拼接，再调用 java 层的 base64 方法传入拼接后的字符串得到加密串作为返回值。



cpp 源码如下：

`
include <jni.h
include <string

extern "C" JNIEXPORT jstring JNICALL
Java_com_cyrus_example_unidbg_UnidbgActivity_sign(JNIEnv env, jobject thiz, jstring content) {
    // 获取 content 字符串
    const char contentChars = envGetStringUTFChars(content, nullptr);

    // 获取静态变量 a 和 非静态变量 b
    jclass clazz = envGetObjectClass(thiz);
    jfieldID aField = envGetStaticFieldID(clazz, "a", "Ljava/lang/String;");
    jfieldID bField = envGetFieldID(clazz, "b", "Ljava/lang/String;");

    jstring a = (jstring) envGetStaticObjectField(clazz, aField);
    jstring b = (jstring) envGetObjectField(thiz, bField);

    // 将 a, content 和 b 拼接
    const char aChars = envGetStringUTFChars(a, nullptr);
    const char bChars = envGetStringUTFChars(b, nullptr);

    std::string combined = std::string(aChars) + contentChars + std::string(bChars);

    // 释放字符串
    envReleaseStringUTFChars(content, contentChars);
    envReleaseStringUTFChars(a, aChars);
    envReleaseStringUTFChars(b, bChars);

    // 调用 base64 方法
    jmethodID base64Method = envGetMethodID(clazz, "base64", "(Ljava/lang/String;)Ljava/lang/String;");
    jstring combinedStr = envNewStringUTF(combined.c_str());
    jstring base64Result = (jstring) envCallObjectMethod(thiz, base64Method, combinedStr);

    return base64Result;
}
