// 将字节数组转换为十六进制字符串
std::string bytesToHex(const std::vector<uint8_t& bytes) {
    std::ostringstream oss;
    for (uint8_t byte : bytes) {
        oss << std::hex << std::setw(2) << std::setfill('0') << (int)byte;
    }
    return oss.str();
}

