    mdContextbuf[0] = (UINT4) 0x67452301;
    mdContextbuf[1] = (UINT4) 0xefcdab89;
    mdContextbuf[2] = (UINT4) 0x98badcfe;
    mdContextbuf[3] = (UINT4) 0x10325476;
