    mdi = (int) ((mdContexti[0]  3) & 0x3F);

    / update number of bits /
    if ((mdContexti[0] + ((UINT4) inLen << 3)) < mdContexti[0])
        mdContexti[1]++;
    mdContexti[0] += ((UINT4) inLen << 3);
    mdContexti[1] += ((UINT4) inLen  29);

    while (inLen) {
    / add new character to buffer, increment mdi /
        mdContextin[mdi++] = inBuf++;

    / transform if necessary /
        if (mdi == 0x40) {
            for (i = 0, ii = 0; i < 16; i++, ii += 4)
                in[i] = (((UINT4) mdContextin[ii + 3]) << 24) |
                        (((UINT4) mdContextin[ii + 2]) << 16) |
                        (((UINT4) mdContextin[ii + 1]) << 8) |
                        ((UINT4) mdContextin[ii]);
            Transform(mdContextbuf, in);
            mdi = 0;
        }
    }
}

/ The routine MD5Final terminates the messagedigest computation and
   ends with the desired message digest in mdContextdigest[0...15].
