void MD5_Final(unsigned char hash[], MD5_CTX mdContext) {
    UINT4 in[16];
    int mdi;
    unsigned int i, ii;
    unsigned int padLen;

    / save number of bits /
    in[14] = mdContexti[0];
    in[15] = mdContexti[1];

    / compute number of bytes mod 64 /
    mdi = (int) ((mdContexti[0]  3) & 0x3F);

    / pad out to 56 mod 64 /
    padLen = (mdi < 56) ? (56  mdi) : (120  mdi);
    MD5_Update(mdContext, PADDING, padLen);

    / append length in bits and transform /
    for (i = 0, ii = 0; i < 14; i++, ii += 4)
        in[i] = (((UINT4) mdContextin[ii + 3]) << 24) |
                (((UINT4) mdContextin[ii + 2]) << 16) |
                (((UINT4) mdContextin[ii + 1]) << 8) |
                ((UINT4) mdContextin[ii]);
    Transform(mdContextbuf, in);

    / store buffer in digest /
    for (i = 0, ii = 0; i < 4; i++, ii += 4) {
        mdContextdigest[ii] = (unsigned char) (mdContextbuf[i] & 0xFF);
        mdContextdigest[ii + 1] =
                (unsigned char) ((mdContextbuf[i]  8) & 0xFF);
        mdContextdigest[ii + 2] =
                (unsigned char) ((mdContextbuf[i]  16) & 0xFF);
        mdContextdigest[ii + 3] =
