function detectOkHttpVersion() {
    Java.perform(function () {
        const hasClass = (name) = {
            try {
                Java.use(name);
                return true;
            } catch (_) {
                return false;
            }
        };

        const log = [];
        log.push("🔍 Scanning for OkHttp...");

